      id        INTEGER PRIMARY KEY AUTOINCREMENT,
      type      TEXT    NOT NULL CHECK(type IN ('symbol', 'file')),
      name      TEXT    NOT NULL,
      file_path TEXT    NOT NULL,
      line      INTEGER,
      column    INTEGER,
