} from './types';

const SCIP_VERSION = 0;

interface WireIndex {
  metadata?: WireMetadata;
  documents: WireDocument[];
  external_symbols?: WireSymbol[];
}

interface WireMetadata {
  version?: number;
  tool_info?: WireToolInfo;
  project_root?: string;
  text_document_encoding?: number;
}

interface WireToolInfo {
  name?: string;
  version?: string;
  arguments?: string[];
}

interface WireDocument {
  language?: string;
  relative_path?: string;
  occurrences?: WireOccurrence[];
  symbols?: WireSymbol[];
  text?: string;
}

interface WireSymbol {
  symbol?: string;
  documentation?: string[];
  relationships?: WireRelationship[];
  kind?: number;
  display_name?: string;
  signature_documentation?: string;
  enclosing_symbol?: string;
}

interface WireRelationship {
  symbol?: string;
  is_reference?: boolean;
  is_implementation?: boolean;
  is_type_definition?: boolean;
  is_inheritance?: boolean;
}

interface WireOccurrence {
  range: number[];
  symbol?: string;
  symbol_roles?: number;
  syntax_kind?: number;
  enclosing_range?: number[];
  override_documentation?: string[];
}

function decodeVarint(bytes: Uint8Array, offset: number): [number, number] {
  let result = 0;
  let shift = 0;
  let pos = offset;

  while (pos < bytes.length) {
    const byte = bytes[pos];
    result |= (byte & 0x7f) << shift;
    pos++;
    if ((byte & 0x80) === 0) {
      break;
    }
    shift += 7;
    if (shift >= 64) {
      throw new Error('Varint too long');
    }
  }

  return [result, pos - offset];
}

function decodeZigzag(value: number): number {
  return (value >>> 1) ^ -(value & 1);
}

function decodeField(
  bytes: Uint8Array,
  offset: number
): [number, number, number, number] | null {
  if (offset >= bytes.length) {
    return null;
  }
  const [tag, tagLen] = decodeVarint(bytes, offset);
  const fieldNumber = tag >>> 3;
  const wireType = tag & 0x7;
  let valueLen = 0;
  let value: number;

  if (wireType === 0) {
    const [v, l] = decodeVarint(bytes, offset + tagLen);
    value = v;
    valueLen = l;
  } else if (wireType === 2) {
    const [len, lenBytes] = decodeVarint(bytes, offset + tagLen);
    value = len;
    valueLen = lenBytes + len;
  } else if (wireType === 5) {
    valueLen = 4;
    value = 0;
  } else if (wireType === 1) {
    valueLen = 8;
    value = 0;
  } else {
    throw new Error(`Unsupported wire type: ${wireType}`);
  }

  return [fieldNumber, wireType, value, tagLen + valueLen];
}

function decodeString(bytes: Uint8Array, offset: number, len: number): string {
  return new TextDecoder().decode(bytes.subarray(offset, offset + len));
}

function parseMetadata(bytes: Uint8Array, offset: number, len: number): Metadata {
  const end = offset + len;
  const metadata: Partial<Metadata> = {
    version: SCIP_VERSION,
    projectRoot: '',
    textDocumentEncoding: TextEncoding.UnspecifiedTextEncoding,
  };
  let toolInfo: Partial<ToolInfo> = { name: '', version: '', arguments: [] };
  let hasToolInfo = false;

  let pos = offset;
  while (pos < end) {
    const field = decodeField(bytes, pos);
    if (!field) break;
    const [fieldNum, wireType, value, fieldLen] = field;
    const fieldEnd = pos + fieldLen;

    switch (fieldNum) {
      case 1:
        if (wireType === 0) metadata.version = value;
        break;
      case 2:
        if (wireType === 2) {
          const toolInfoData = parseToolInfo(bytes, pos + fieldLen - value, value);
          toolInfo = toolInfoData;
          hasToolInfo = true;
        }
        break;
      case 3:
        if (wireType === 2) {
          metadata.projectRoot = decodeString(bytes, pos + fieldLen - value, value);
        }
        break;
      case 4:
        if (wireType === 0) metadata.textDocumentEncoding = value;
        break;
    }
    pos = fieldEnd;
  }

  if (hasToolInfo) {
    metadata.toolInfo = toolInfo as ToolInfo;
  }

  return metadata as Metadata;
}

function parseToolInfo(bytes: Uint8Array, offset: number, len: number): ToolInfo {
  const end = offset + len;
  const toolInfo: Partial<ToolInfo> = { name: '', version: '', arguments: [] };

  let pos = offset;
  while (pos < end) {
    const field = decodeField(bytes, pos);
    if (!field) break;
    const [fieldNum, wireType, value, fieldLen] = field;

    switch (fieldNum) {
      case 1:
        if (wireType === 2) {
          toolInfo.name = decodeString(bytes, pos + fieldLen - value, value);
        }
        break;
      case 2:
        if (wireType === 2) {
          toolInfo.version = decodeString(bytes, pos + fieldLen - value, value);
        }
        break;
      case 3:
        if (wireType === 2) {
          const arg = decodeString(bytes, pos + fieldLen - value, value);
          toolInfo.arguments = toolInfo.arguments || [];
          toolInfo.arguments.push(arg);
        }
        break;
    }
    pos += fieldLen;
  }

  return toolInfo as ToolInfo;
}

function parseRelationship(bytes: Uint8Array, offset: number, len: number): Relationship {
  const end = offset + len;
  const rel: Partial<Relationship> = {
    symbol: '',
    isReference: false,
    isImplementation: false,
    isTypeDefinition: false,
    isInheritance: false,
  };

  let pos = offset;
  while (pos < end) {
    const field = decodeField(bytes, pos);
    if (!field) break;
    const [fieldNum, wireType, value, fieldLen] = field;

    switch (fieldNum) {
      case 1:
        if (wireType === 2) {
          rel.symbol = decodeString(bytes, pos + fieldLen - value, value);
        }
        break;
      case 2:
        if (wireType === 0) rel.isReference = value !== 0;
        break;
      case 3:
        if (wireType === 0) rel.isImplementation = value !== 0;
        break;
      case 4:
        if (wireType === 0) rel.isTypeDefinition = value !== 0;
        break;
      case 5:
        if (wireType === 0) rel.isInheritance = value !== 0;
        break;
    }
    pos += fieldLen;
  }

  return rel as Relationship;
}

function parseSymbolInformation(bytes: Uint8Array, offset: number, len: number): SymbolInformation {
  const end = offset + len;
  const sym: Partial<SymbolInformation> = {
    symbol: '',
    documentation: [],
    relationships: [],
    kind: SymbolKind.UnspecifiedSymbolKind,
    displayName: '',
    signatureDocumentation: '',
    enclosingSymbol: '',
  };

  let pos = offset;
  while (pos < end) {
    const field = decodeField(bytes, pos);
    if (!field) break;
    const [fieldNum, wireType, value, fieldLen] = field;
    const fieldEnd = pos + fieldLen;

    switch (fieldNum) {
      case 1:
        if (wireType === 2) {
          sym.symbol = decodeString(bytes, pos + fieldLen - value, value);
        }
        break;
      case 2:
        if (wireType === 2) {
          const doc = decodeString(bytes, pos + fieldLen - value, value);
          sym.documentation!.push(doc);
        }
        break;
      case 3:
        if (wireType === 2) {
          const rel = parseRelationship(bytes, pos + fieldLen - value, value);
          sym.relationships!.push(rel);
        }
        break;
      case 4:
        if (wireType === 0) sym.kind = value;
        break;
      case 5:
        if (wireType === 2) {
          sym.displayName = decodeString(bytes, pos + fieldLen - value, value);
        }
        break;
      case 6:
        if (wireType === 2) {
          sym.signatureDocumentation = decodeString(bytes, pos + fieldLen - value, value);
        }
        break;
      case 7:
        if (wireType === 2) {
          sym.enclosingSymbol = decodeString(bytes, pos + fieldLen - value, value);
        }
        break;
    }
    pos = fieldEnd;
  }

  return sym as SymbolInformation;
}

function parseOccurrence(bytes: Uint8Array, offset: number, len: number): Occurrence {
  const end = offset + len;
  const occ: Partial<Occurrence> = {
    range: { start: { line: 0, character: 0 }, end: { line: 0, character: 0 } },
    symbol: '',
    symbolRoles: SymbolRole.UnspecifiedSymbolRole,
    syntaxKind: SyntaxKind.UnspecifiedSyntaxKind,
    overrideDocumentation: [],
  };
  const rangeValues: number[] = [];

  let pos = offset;
  while (pos < end) {
    const field = decodeField(bytes, pos);
    if (!field) break;
    const [fieldNum, wireType, value, fieldLen] = field;
    const fieldEnd = pos + fieldLen;

    switch (fieldNum) {
      case 1:
        if (wireType === 0 || wireType === 2) {
          if (wireType === 2) {
            const rangeData = bytes.subarray(pos + fieldLen - value, pos + fieldLen);
            let rangePos = 0;
            while (rangePos < rangeData.length) {
              const [v, l] = decodeVarint(rangeData, rangePos);
              rangeValues.push(decodeZigzag(v));
              rangePos += l;
            }
          } else {
            rangeValues.push(decodeZigzag(value));
          }
        }
        break;
      case 2:
        if (wireType === 2) {
          occ.symbol = decodeString(bytes, pos + fieldLen - value, value);
        }
        break;
      case 3:
        if (wireType === 0) occ.symbolRoles = value;
        break;
      case 4:
        if (wireType === 0) occ.syntaxKind = value;
        break;
      case 5:
        if (wireType === 2) {
          // enclosing_range - packed or unpacked
          const enclosingData = bytes.subarray(pos + fieldLen - value, pos + fieldLen);
          let enclosingPos = 0;
          const enclosingValues: number[] = [];
          while (enclosingPos < enclosingData.length) {
            const [v, l] = decodeVarint(enclosingData, enclosingPos);
            enclosingValues.push(decodeZigzag(v));
            enclosingPos += l;
          }
          if (enclosingValues.length >= 3) {
            occ.enclosingRange = {
              start: { line: enclosingValues[0], character: enclosingValues[1] },
              end: {
                line: enclosingValues[enclosingValues.length > 3 ? 2 : 0],
                character: enclosingValues[enclosingValues.length > 3 ? 3 : 2],
              },
            };
          }
        }
        break;
      case 6:
        if (wireType === 2) {
          const doc = decodeString(bytes, pos + fieldLen - value, value);
          occ.overrideDocumentation!.push(doc);
        }
        break;
    }
    pos = fieldEnd;
  }

  if (rangeValues.length >= 3) {
    if (rangeValues.length === 3) {
      // Compact 3-int format: [start_line, start_char, end_char]
      occ.range = {
        start: { line: rangeValues[0], character: rangeValues[1] },
        end: { line: rangeValues[0], character: rangeValues[2] },
      };
    } else {
      // Full 4-int format: [start_line, start_char, end_line, end_char]
      occ.range = {
        start: { line: rangeValues[0], character: rangeValues[1] },
        end: { line: rangeValues[2], character: rangeValues[3] },
      };
    }
  }

  return occ as Occurrence;
}

function parseDocument(bytes: Uint8Array, offset: number, len: number): Document {
  const end = offset + len;
  const doc: Partial<Document> = {
    language: '',
    relativePath: '',
    occurrences: [],
    symbols: [],
    text: '',
  };

  let pos = offset;
  while (pos < end) {
    const field = decodeField(bytes, pos);
    if (!field) break;
    const [fieldNum, wireType, value, fieldLen] = field;
    const fieldEnd = pos + fieldLen;

    switch (fieldNum) {
      case 1:
        if (wireType === 2) {
          doc.language = decodeString(bytes, pos + fieldLen - value, value);
        }
        break;
      case 2:
        if (wireType === 2) {
          doc.relativePath = decodeString(bytes, pos + fieldLen - value, value);
        }
        break;
      case 3:
        if (wireType === 2) {
          const occ = parseOccurrence(bytes, pos + fieldLen - value, value);
          doc.occurrences!.push(occ);
        }
        break;
      case 4:
        if (wireType === 2) {
          const sym = parseSymbolInformation(bytes, pos + fieldLen - value, value);
          doc.symbols!.push(sym);
        }
        break;
      case 5:
        if (wireType === 2) {
          doc.text = decodeString(bytes, pos + fieldLen - value, value);
        }
        break;
    }
    pos = fieldEnd;
  }

  return doc as Document;
}

function parseIndexInternal(bytes: Uint8Array): Index {
  const index: Partial<Index> = {
    documents: [],
    externalSymbols: [],
  };

  let pos = 0;
  while (pos < bytes.length) {
    const field = decodeField(bytes, pos);
    if (!field) break;
    const [fieldNum, wireType, value, fieldLen] = field;
    const fieldEnd = pos + fieldLen;

    switch (fieldNum) {
      case 1:
        if (wireType === 2) {
          index.metadata = parseMetadata(bytes, pos + fieldLen - value, value);
        }
        break;
      case 2:
        if (wireType === 2) {
          const doc = parseDocument(bytes, pos + fieldLen - value, value);
          index.documents!.push(doc);
        }
        break;
      case 3:
        if (wireType === 2) {
          const sym = parseSymbolInformation(bytes, pos + fieldLen - value, value);
          index.externalSymbols!.push(sym);
        }
        break;
    }
    pos = fieldEnd;
  }

  return index as Index;
}

export function parseSymbol(symbol: string): ParsedSymbol {
  const parts = symbol.split(' ');
  if (parts.length < 2) {
    throw new Error(`Invalid symbol format: ${symbol}`);
  }

  const scheme = parts[0];
  let packagePart: Package | null = null;
  const descriptors: Descriptor[] = [];

  for (let i = 1; i < parts.length; i++) {
    const part = parts[i];
    if (part.startsWith('pkg:')) {
      const pkgContent = part.slice(4);
      const pkgParts = pkgContent.split('/');
      if (pkgParts.length >= 3) {
        packagePart = {
          manager: pkgParts[0],
          name: pkgParts[1],
          version: pkgParts[2],
        };
      }
    } else if (part.startsWith('local:')) {
      descriptors.push({
        name: part.slice(6),
        suffix: DescriptorSuffix.Local,
        disambiguator: '',
      });
    } else {
      // Parse descriptor
      const descriptor = parseDescriptor(part);
      if (descriptor) {
        descriptors.push(descriptor);
      }
    }
  }

  return { scheme, package: packagePart, descriptors };
}

function parseDescriptor(part: string): Descriptor | null {
  if (part.length === 0) return null;

  const lastChar = part[part.length - 1];
  let suffix: DescriptorSuffix;
  let name = part;
  let disambiguator = '';

  switch (lastChar) {
    case '/':
      suffix = DescriptorSuffix.Package;
      name = part.slice(0, -1);
      break;
    case '#':
      suffix = DescriptorSuffix.Type;
      name = part.slice(0, -1);
      break;
    case '.':
      suffix = DescriptorSuffix.Term;
      name = part.slice(0, -1);
      break;
    case '(':
      suffix = DescriptorSuffix.Method;
      name = part.slice(0, -1);
      break;
    case '[':
      suffix = DescriptorSuffix.TypeParameter;
      name = part.slice(0, -1);
      break;
    case ',':
      suffix = DescriptorSuffix.Parameter;
      name = part.slice(0, -1);
      break;
    case ':':
      suffix = DescriptorSuffix.Meta;
      name = part.slice(0, -1);
      break;
    default:
      suffix = DescriptorSuffix.Term;
  }

  // Check for disambiguator in parentheses for methods
  const parenIndex = name.indexOf('(');
  if (parenIndex > 0 && suffix === DescriptorSuffix.Method) {
    disambiguator = name.slice(parenIndex + 1).replace(')', '');
    name = name.slice(0, parenIndex);
  }

  return { name, suffix, disambiguator };
}

export function parseIndex(buffer: Uint8Array | Buffer): ParseResult {
  const bytes = buffer instanceof Buffer ? new Uint8Array(buffer) : buffer;
  const index = parseIndexInternal(bytes);

  const symbols: ExtractedSymbol[] = [];
  const relationships: ExtractedRelationship[] = [];

  for (const doc of index.documents) {
    for (const sym of doc.symbols) {
      const definitionOcc = doc.occurrences.find(
        (o) => o.symbol === sym.symbol && (o.symbolRoles & SymbolRole.Definition) !== 0
      );

      const extracted: ExtractedSymbol = {
        symbol: sym.symbol,
        kind: sym.kind,
        displayName: sym.displayName,
        documentation: sym.documentation,
        filePath: doc.relativePath,
        position: definitionOcc ? definitionOcc.range.start : { line: 0, character: 0 },
        relationships: sym.relationships,
      };
      symbols.push(extracted);

      for (const rel of sym.relationships) {
        const types: ExtractedRelationship['type'][] = [];
        if (rel.isReference) types.push('reference');
        if (rel.isImplementation) types.push('implementation');
        if (rel.isTypeDefinition) types.push('typeDefinition');
        if (rel.isInheritance) types.push('inheritance');

        for (const type of types) {
          relationships.push({
            sourceSymbol: sym.symbol,
            targetSymbol: rel.symbol,
            type,
          });
        }
      }
    }
  }

  for (const sym of index.externalSymbols) {
    const extracted: ExtractedSymbol = {
      symbol: sym.symbol,
      kind: sym.kind,
      displayName: sym.displayName,
      documentation: sym.documentation,
      filePath: '',
      position: { line: 0, character: 0 },
      relationships: sym.relationships,
    };
    symbols.push(extracted);

    for (const rel of sym.relationships) {
      const types: ExtractedRelationship['type'][] = [];
      if (rel.isReference) types.push('reference');
      if (rel.isImplementation) types.push('implementation');
      if (rel.isTypeDefinition) types.push('typeDefinition');
      if (rel.isInheritance) types.push('inheritance');

      for (const type of types) {
        relationships.push({
          sourceSymbol: sym.symbol,
          targetSymbol: rel.symbol,
          type,
        });
      }
    }
  }

  return { index, symbols, relationships };
}

export function getOccurrencesForSymbol(index: Index, symbol: string): Occurrence[] {
  const result: Occurrence[] = [];
  for (const doc of index.documents) {
    for (const occ of doc.occurrences) {
      if (occ.symbol === symbol) {
        result.push(occ);
      }
    }
  }
  return result;
}

export function getDefinitions(index: Index): ExtractedSymbol[] {
  const result: ExtractedSymbol[] = [];
  for (const doc of index.documents) {
    for (const sym of doc.symbols) {
      const definitionOcc = doc.occurrences.find(
        (o) => o.symbol === sym.symbol && (o.symbolRoles & SymbolRole.Definition) !== 0
      );
      result.push({
        symbol: sym.symbol,
        kind: sym.kind,
        displayName: sym.displayName,
        documentation: sym.documentation,
        filePath: doc.relativePath,
        position: definitionOcc ? definitionOcc.range.start : { line: 0, character: 0 },
        relationships: sym.relationships,
      });
    }
  }
  return result;
}

export function getReferences(index: Index, symbol: string): Occurrence[] {
  const result: Occurrence[] = [];
  for (const doc of index.documents) {
    for (const occ of doc.occurrences) {
      if (occ.symbol === symbol && (occ.symbolRoles & SymbolRole.Definition) === 0) {
        result.push(occ);
      }
    }
  }
  return result;
}

