    82→function extractSymbols(doc: Record<string, unknown>): ScipSymbol[] {
    83→  const symbols: ScipSymbol[] = [];
    84→  const externalSymbols: Record<string, unknown> =
    85→    (doc.external_symbols as Record<string, unknown>) ?? {};
    86→  const internalSymbols: Record<string, unknown> =
    87→    (doc.internal_symbols as Record<string, unknown>) ?? {};
    88→  const documents: Record<string, unknown> =
    89→    (doc.documents as Record<string, unknown>) ?? {};
    90→
    91→  const allSymbols = { ...externalSymbols, ...internalSymbols };
    92→  const pathByDocId: Record<string, string> = {};
    93→
    94→  for (const [docId, docData] of Object.entries(documents)) {
    95→    const relativePath = (docData as Record<string, unknown>).relative_path as
    96→      | string
    97→      | undefined;
    98→    if (relativePath) pathByDocId[docId] = relativePath;
    99→  }
   100→
   101→  for (const [symbolKey, symData] of Object.entries(allSymbols)) {
   102→    const sym = symData as Record<string, unknown>;
   103→    const relationships = sym.relationships as Record<string, unknown> | undefined;
   104→    const defRef = relationships?.definition_reference as
   105→      | Record<string, unknown>
   106→      | undefined;
   107→    const docRef = defRef?.document as string | undefined;
   108→
   109→    symbols.push({
   110→      name: symbolKey,
   111→      kind: (sym.kind as string) ?? "unknown",
   112→      definition: defRef
   113→        ? `${pathByDocId[docRef ?? ""] ?? docRef}:${defRef.start_line ?? 0}`
   114→        : undefined,
   115→      documentPath: docRef ? pathByDocId[docRef] : undefined,
   116→    });
   117→  }
