   122→export async function buildIndex(
   123→  projectPath: string,
   124→  projectType: ProjectType
   125→): Promise<IndexResult> {
   126→  const spec = indexerCommand(projectType);
   127→  if (!spec) {
   128→    return { success: false, error: `unsupported project type: ${projectType}` };
   129→  }
