   155→    );
   156→    const getDocId = db.prepare(
   157→      "SELECT id FROM documents WHERE path = ?"
   158→    );
   159→    const insertSym = db.prepare(
   160→      "INSERT INTO symbols (name, kind, definition, document_id) VALUES (?, ?, ?, ?)"
   161→    );
   162→
   163→    const tx = db.transaction(() => {
   164→      const docPaths = new Set<string>();
   165→      let symCount = 0;
   166→
   167→      for (const sym of symbols) {
   168→        if (sym.documentPath) docPaths.add(sym.documentPath);
   169→      }
