   181→        symCount++;
   182→      }
   183→
   184→      return { documentCount: docPaths.size, symbolCount: symCount };
   185→    });
   186→
   187→    const counts = tx();
   188→    db.close();
   189→
   190→    return {
   191→      success: true,
   192→      dbPath,
   193→      documentCount: counts.documentCount,
   194→      symbolCount: counts.symbolCount,
   195→    };
   196→  } catch (err) {
   197→    db.close();
   198→    const msg = err instanceof Error ? err.message : String(err);
