   340→    // Button interactions (permission allow/deny, plan approve/reject)
   341→    if (interaction.isButton()) {
   342→      const customId = interaction.customId;
   343→      if (!customId.startsWith('perm:')) return;
   344→
   345→      const parts = customId.split(':');
   346→      const decision = parts[1] as 'allow' | 'deny' | 'allow_all';
   347→      const requestId = parts.slice(2).join(':');
   348→
   349→      if (this.onPermissionDecision) {
   350→        this.onPermissionDecision(requestId, decision);
   351→      }
   352→
   353→      const isDeny = decision === 'deny';
   354→      const emoji = isDeny ? '\u274c' : '\u2705';
   355→      const label = isDeny ? '已拒绝' : decision === 'allow_all' ? '已批准（同类工具全放行）' : '已批准';
   356→      await interaction.update({
   357→        components: [],
   358→        embeds: [{
   359→          ...interaction.message.embeds[0]?.toJSON(),
