   395→  private async handleHubCommand(msg: Message): Promise<void> {
   396→    const text = this.normalizeInboundText(msg.content);
   397→    if (!text.startsWith('!') && !text.startsWith('/')) return;
   398→
   399→    const spaceIdx = text.indexOf(' ');
   400→    const rawCommand = spaceIdx === -1 ? text : text.slice(0, spaceIdx);
   401→    const args = spaceIdx === -1 ? '' : text.slice(spaceIdx + 1).trim();
   402→    const command = rawCommand.startsWith('/') ? `!${rawCommand.slice(1)}` : rawCommand;
   403→
   404→    switch (command) {
   405→      case '!status': {
   406→        const sessions = this.registry.listVisible();
   407→        if (sessions.length === 0) {
   408→          await msg.reply('当前没有可见的活跃 session。');
   409→          return;
   410→        }
   411→        const lines = sessions.map(s => {
   412→          const thread = s.threadId ? `<#${s.threadId}>` : '未绑定 thread';
   413→          return `• **${s.project}/${s.branch}** [${s.sessionId.slice(0, 6)}] — ${thread} — ${s.filterLevel} — ${s.status}`;
   414→        });
   415→        await msg.reply(lines.join('\n'));
   416→        break;
   417→      }
   418→      default:
   419→        if (this.onHubCommand) {
   420→          const ctx: HubReplyContext = { reply: (text) => msg.reply(text).then(() => {}) };
   421→          this.onHubCommand(command, args, ctx);
   422→        }
   423→    }
   424→  }
   425→
   426→  private normalizeInboundText(text: string): string {
   427→    const trimmed = text.trim();
   428→    if (!trimmed) return trimmed;
   429→    if (trimmed.startsWith('！')) return `!${trimmed.slice(1)}`;
   430→    if (trimmed.startsWith('／')) return `/${trimmed.slice(1)}`;
   431→    return trimmed;
   432→  }
