   505→  private async cleanupLegacyEndedCards(): Promise<void> {
   506→    try {
   507→      const channel = await this.client.channels.fetch(this.config.discord.hubChannelId);
   508→      if (!channel || !('messages' in channel)) return;
   509→
   510→      let before: string | undefined;
   511→      let scanned = 0;
   512→      while (scanned < 1000) {
   513→        const messages = await (channel as TextChannel).messages.fetch({ limit: 100, before });
   514→        if (messages.size === 0) break;
   515→
   516→        for (const msg of messages.values()) {
   517→          scanned += 1;
   518→          if (msg.author.id !== this.client.user?.id) continue;
   519→          const embed = msg.embeds[0];
   520→          if (!embed) continue;
   521→          const description = embed.description || '';
   522→          const looksLikeSessionCard = description.includes('**Session:**')
   523→            && description.includes('**Directory:**')
   524→            && description.includes('**Status:**');
   525→          const isLegacyEndedCard = looksLikeSessionCard && description.includes('Ended');
   526→
   527→          if (!isLegacyEndedCard) continue;
   528→          await msg.delete().catch(() => undefined);
   529→        }
   530→
   531→        before = messages.last()?.id;
   532→        if (!before) break;
   533→      }
   534→    } catch (err) {
   535→      console.warn('[discord] Failed to cleanup legacy ended cards:', err);
   536→    }
   537→  }
   538→
   539→  private chunkText(text: string, limit: number): string[] {
   540→    if (text.length <= limit) return [text];
   541→    const chunks: string[] = [];
   542→    let remaining = text;
   543→    while (remaining.length > 0) {
   544→      if (remaining.length <= limit) {
   545→        chunks.push(remaining);
   546→        break;
   547→      }
   548→      // Try to break at newline
   549→      let breakAt = remaining.lastIndexOf('\n', limit);
   550→      if (breakAt <= 0) breakAt = limit;
   551→      chunks.push(remaining.slice(0, breakAt));
   552→      remaining = remaining.slice(breakAt);
   553→    }
   554→    return chunks;
   555→  }
   556→}
