   236→  private async handleSdkText(sessionId: string, text: string): Promise<void> {
   237→    const session = this.registry.getSession(sessionId);
   238→    if (!session?.threadId) return;
   239→
   240→    // Track full response for title generation
   241→    const prev = this.sdkResponseText.get(sessionId) || '';
   242→    this.sdkResponseText.set(sessionId, prev + text);
   243→
   244→    let buf = this.sdkTextBuffers.get(sessionId);
   245→    if (!buf) {
   246→      buf = { text: '' };
   247→      this.sdkTextBuffers.set(sessionId, buf);
   248→    }
   249→    buf.text += text;
   250→
   251→    // Debounce: edit the streaming message every 800ms
   252→    if (buf.timer) clearTimeout(buf.timer);
   253→    buf.timer = setTimeout(() => {
   254→      this.flushSdkText(sessionId).catch(() => {});
   255→    }, 800);
   256→  }
   257→
   258→  private async flushSdkText(sessionId: string): Promise<void> {
   259→    const buf = this.sdkTextBuffers.get(sessionId);
   260→    if (!buf || !buf.text) return;
   261→
   262→    const session = this.registry.getSession(sessionId);
   263→    if (!session?.threadId) return;
   264→
   265→    const brand = getAgentBrand(session.agent);
   266→    const truncated = buf.text.length > 3800
   267→      ? buf.text.slice(0, 3800) + `\n*[${buf.text.length} chars total]*`
   268→      : buf.text;
   269→
   270→    const embed = {
   271→      author: { name: `${brand.label}`, ...(brand.iconUrl ? { icon_url: brand.iconUrl } : {}) },
   272→      description: truncated,
   273→      color: brand.color,
   274→    };
   275→
   276→    if (buf.messageId) {
   277→      // Edit existing message (streaming update)
   278→      const ok = await this.discord.editThreadMessage(session.threadId, buf.messageId, { embed });
   279→      if (!ok) {
   280→        // Edit failed (message deleted?), send new
   281→        const newId = await this.discord.sendToThread(session.threadId, { embed });
   282→        if (newId) buf.messageId = newId;
   283→      }
   284→    } else {
   285→      // First chunk — send new message, remember ID for edits
   286→      const msgId = await this.discord.sendToThread(session.threadId, { embed });
   287→      if (msgId) buf.messageId = msgId;
   288→    }
   289→  }
   290→
   291→  /** Finalize streaming: flush remaining text, reset buffer */
   292→  private async finalizeSdkText(sessionId: string): Promise<void> {
   293→    await this.flushSdkText(sessionId);
   294→    const buf = this.sdkTextBuffers.get(sessionId);
   295→    if (buf) {
   296→      buf.text = '';
   297→      buf.messageId = undefined;
   298→      if (buf.timer) clearTimeout(buf.timer);
   299→    }
   300→  }
