   309→  private async handleSdkStreamError(sessionId: string, error: string): Promise<void> {
   310→    const session = this.registry.getSession(sessionId);
   311→    if (!session?.threadId) return;
   312→
   313→    const isSignatureError = error.includes('signature') || error.includes('thinking block');
   314→    const savedPrompt = this.sdkLastPrompt.get(sessionId);
   315→
   316→    // Auto-retry: resume failed due to cross-key → start fresh with same prompt
   317→    if (isSignatureError && savedPrompt && !this.sdkRetriedFresh.has(sessionId) && this.sdkManager) {
   318→      this.sdkRetriedFresh.add(sessionId);
   319→      this.sdkLastPrompt.delete(sessionId);
   320→
   321→      await this.discord.sendToThread(session.threadId, {
   322→        embed: {
   323→          title: '⚠️ CC session key 不匹配，自动切换为独立对话',
   324→          description: '本次及后续回复不会出现在 CC 中',
   325→          color: 0xFAA307,
   326→        },
   327→      });
   328→
   329→      try {
   330→        await this.sdkManager.startSession(savedPrompt, {
   331→          cwd: session.cwd,
   332→          model: session.model,
   333→          provider: session.provider,
   334→        });
   335→        console.log(`[router] Auto-retry fresh for ${sessionId.slice(0, 8)}`);
   336→      } catch (err) {
   337→        const msg = err instanceof Error ? err.message : String(err);
   338→        await this.discord.sendToThread(session.threadId, `❌ ${msg}`);
   339→      }
   340→      return;
   341→    }
   342→
   343→    // Normal error
   344→    await this.discord.sendToThread(session.threadId, {
   345→      embed: {
   346→        title: '🚨 Error',
   347→        description: error.slice(0, 4000),
   348→        color: 0xED4245,
   349→      },
   350→    });
   351→  }
