   357→  private async handleSdkTool(sessionId: string, name: string, summary: string): Promise<void> {
   358→    // Finalize streaming text before showing tool card (starts new text block after)
   359→    await this.finalizeSdkText(sessionId);
   360→
   361→    const session = this.registry.getSession(sessionId);
   362→    if (!session?.threadId) return;
   363→
   364→    // Auto-detect cwd from file access patterns
   365→    if (summary.startsWith('/') && !this.sdkCwdLocked.has(sessionId)) {
   366→      this.trackSdkPath(sessionId, summary);
   367→    }
   368→
   369→    const titleLine = `🔧 ${name}${summary ? ` — ${summary}` : ''}`;
   370→    await this.discord.sendToThread(session.threadId, {
   371→      embed: {
   372→        title: titleLine.length > 256 ? titleLine.slice(0, 253) + '...' : titleLine,
   373→        color: 0x57F287,
   374→        timestamp: new Date().toISOString(),
   375→      },
   376→    });
   377→  }
