   379→  /**
   380→   * Track file paths from SDK tool calls.
   381→   * After 3+ paths sharing a common project root, auto-update session cwd.
   382→   */
   383→  private trackSdkPath(sessionId: string, filePath: string): void {
   384→    if (!this.sdkFilePaths.has(sessionId)) {
   385→      this.sdkFilePaths.set(sessionId, []);
   386→    }
   387→    const paths = this.sdkFilePaths.get(sessionId)!;
   388→    paths.push(filePath);
   389→    if (paths.length < 3) return;
   390→
   391→    // Find common root (deepest shared directory)
   392→    const segments = paths.map(p => p.split('/'));
   393→    const common: string[] = [];
   394→    for (let i = 0; i < segments[0].length; i++) {
   395→      const seg = segments[0][i];
   396→      if (segments.every(s => s[i] === seg)) {
   397→        common.push(seg);
   398→      } else {
   399→        break;
   400→      }
   401→    }
   402→    const commonRoot = common.join('/');
   403→
   404→    // Skip if root is too shallow ($HOME or above)
   405→    const home = getUserHome();
   406→    if (!commonRoot || commonRoot === home || commonRoot.split('/').length <= home.split('/').length) {
   407→      return;
   408→    }
   409→
   410→    // Find the likely project root (directory containing .git, package.json, etc.)
   411→    const projectRoot = this.findProjectRoot(commonRoot);
   412→    const session = this.registry.getSession(sessionId);
   413→    if (!session) return;
   414→
   415→    // Only update if different from current cwd and not already a project dir
   416→    if (session.cwd === projectRoot) return;
   417→
   418→    const oldProject = session.project;
   419→    session.cwd = projectRoot;
   420→    session.project = projectRoot.split('/').pop() || session.project;
   421→    this.store.setSession(session);
   422→    this.sdkCwdLocked.add(sessionId); // Don't re-detect after auto-update
   423→
   424→    // Notify in thread
   425→    if (session.threadId) {
   426→      this.discord.sendToThread(session.threadId, {
   427→        embed: {
   428→          title: `📂 Auto-detected: ${oldProject} → ${session.project}`,
   429→          description: `\`${collapseHome(projectRoot)}\``,
   430→          color: 0x5865F2,
   431→        },
   432→      }).catch(() => {});
   433→    }
   434→
   435→    // Refresh hub card
   436→    this.registry.emit('session:active', session);
   437→    console.log(`[router] Auto-cwd: ${sessionId.slice(0, 8)} → ${projectRoot}`);
   438→  }
   439→
   440→  /** Walk up from a path to find the nearest project root */
   441→  private findProjectRoot(dir: string): string {
   442→    const markers = ['.git', 'package.json', 'Cargo.toml', 'go.mod', 'pyproject.toml', 'pom.xml'];
   443→    let current = dir;
   444→    const home = getUserHome();
   445→    while (current.length > home.length) {
   446→      for (const marker of markers) {
   447→        try {
   448→          fs.statSync(`${current}/${marker}`);
   449→          return current;
   450→        } catch { /* continue */ }
   451→      }
   452→      const parent = current.slice(0, current.lastIndexOf('/'));
   453→      if (parent === current) break;
   454→      current = parent;
   455→    }
   456→    return dir; // fallback to the common root itself
   457→  }
