   548→  // ── Hub channel commands ──
   549→
   550→  private async handleHubCommand(command: string, args: string, ctx: HubReplyContext): Promise<void> {
   551→    const normalized = this.normalizeCommand(command);
   552→    switch (normalized) {
   553→      case '!new': {
   554→        if (!this.sdkManager || !this.mmsEnv) {
   555→          await ctx.reply('当前未配置 SDK。');
   556→          return;
   557→        }
   558→        // /new [model] [cwd] prompt...
   559→        // model: exact name or prefix (e.g. "kimi" → "kimi-for-coding")
   560→        // cwd: full path, ~, or project name shortcut (matches recent session projects)
   561→        const parts = args.split(/\s+/);
   562→        let model = this.mmsEnv.getDefaultModel();
   563→        let cwd = getUserHome();
   564→        let promptParts = [...parts];
   565→
   566→        // Check if first arg matches a model (fuzzy)
   567→        if (parts[0] && this.mmsEnv.resolveModel(parts[0])) {
   568→          model = this.mmsEnv.resolveModel(parts[0])!.resolvedId;
   569→          promptParts = parts.slice(1);
   570→        }
   571→
   572→        // Check if next arg is a cwd specifier
   573→        if (promptParts[0]) {
   574→          const cwdArg = promptParts[0];
   575→          if (cwdArg.startsWith('/')) {
   576→            cwd = cwdArg;
   577→            promptParts = promptParts.slice(1);
   578→          } else if (cwdArg.startsWith('~')) {
   579→            cwd = expandHome(cwdArg);
   580→            promptParts = promptParts.slice(1);
   581→          } else if (promptParts.length >= 2) {
   582→            // Only try project shortcut if there's still a prompt after it
   583→            const matched = this.resolveCwdShortcut(cwdArg);
   584→            if (matched) {
   585→              cwd = matched;
   586→              promptParts = promptParts.slice(1);
   587→            }
   588→          }
   589→        }
   590→
   591→        const prompt = promptParts.join(' ');
   592→        if (!prompt) {
   593→          await ctx.reply('用法: `!new [model] [cwd] <prompt>`\nmodel / cwd 都支持模糊匹配。');
   594→          return;
   595→        }
   596→
   597→        const provider = this.mmsEnv.resolveProvider(model);
   598→        await ctx.reply(`正在启动: **${model}** in \`${collapseHome(cwd)}\`...`);
   599→
   600→        try {
   601→          const sessionId = await this.sdkManager.startSession(prompt, {
   602→            cwd,
   603→            model,
   604→            provider,
   605→          });
   606→          console.log(`[router] /new → SDK session started: ${sessionId.slice(0, 12)}`);
   607→
   608→          // Wait for thread creation
   609→          await new Promise(r => setTimeout(r, 2000));
   610→          const session = this.registry.getSession(sessionId);
   611→          if (session) {
   612→            // Set title from prompt for hub card
   613→            const shortPrompt = prompt.length > 60 ? prompt.slice(0, 57) + '...' : prompt;
   614→            session.title = shortPrompt;
   615→            session.model = model;
   616→            this.store.setSession(session);
   617→            this.registry.emit('session:active', session);
   618→            if (session.threadId) {
   619→              await ctx.reply(`Thread created: ${session.threadId}`);
   620→            }
   621→          }
   622→        } catch (err) {
   623→          const errMsg = err instanceof Error ? err.message : String(err);
   624→          await ctx.reply(`启动失败: ${errMsg}`);
   625→        }
   626→        break;
   627→      }
   628→
   629→      case '!clean': {
   630→        // Finalize all non-dead sessions and clean up hub cards
   631→        let cleaned = 0;
   632→        for (const session of this.registry.listAll()) {
   633→          if (session.status === 'dead') continue;
   634→          this.registry.finalizeEnded(session.sessionId);
   635→          cleaned++;
   636→        }
   637→        await ctx.reply(cleaned > 0 ? `已清理 ${cleaned} 个 session。` : '当前没有可清理的 session。');
   638→        break;
