   838→  private handlePermissionDecision(permissionId: string, decision: 'allow' | 'deny' | 'allow_all'): void {
   839→    // Try SDK interaction first (for SDK-based sessions)
   840→    if (this.sdkManager && this.sdkManager.resolveInteraction(permissionId, decision)) {
   841→      console.log(`[router] SDK permission ${permissionId.slice(0, 12)} ${decision}`);
   842→      return;
   843→    }
   844→
   845→    // Fall back to IPC socket (for hook-based sessions) — IPC only knows allow/deny
   846→    const ipcDecision = decision === 'deny' ? 'deny' : 'allow';
   847→    const resolved = this.ipc.resolvePermission(permissionId, ipcDecision);
   848→    if (resolved) {
   849→      this.store.deletePendingPermission(permissionId);
   850→      console.log(`[router] Permission ${permissionId.slice(0, 8)} ${decision}`);
   851→    } else {
   852→      console.warn(`[router] No waiting socket for permission ${permissionId.slice(0, 8)}`);
   853→    }
   854→  }
