   981→  private async handleThreadCommand(session: CLISession, command: string): Promise<void> {
   982→    const parts = command.split(/\s+/);
   983→    const cmd = this.normalizeCommand(parts[0].toLowerCase());
   984→    const mode = this.getSessionInteractionMode(session);
   985→
   986→    switch (cmd) {
   987→      case '!help': {
   988→        if (session.threadId) {
   989→          await this.discord.sendToThread(session.threadId, [
   990→            `**模式:** ${mode.label}`,
   991→            mode.hint,
   992→            '',
   993→            '**命令:**',
   994→            '`!help` — 显示这份帮助',
   995→            '`!distill` — 生成 MindKeeper checkpoint（`dst-*`），不可用时回退到本地摘要',
   996→            '`恢复 <dst-id>` / `继续 <dst-id>` — 读取恢复口令，不再误发给 SDK',
   997→            '`!filter full|summary|compact|silent` — 切换过滤级别',
   998→            '`!info` — 查看当前 session 信息',
   999→            '`!model <name>` — 切换 SDK session 的 model',
  1000→            '`!models` — 列出可用 model（来源于本地 MMS routes）',
  1001→            '`!provider <id>` — 覆盖 SDK session 的 provider',
  1002→            '`!cd <path-or-name>` — 修改后续 SDK turn 的 cwd',
  1003→            '`!fork [prompt]` — 从当前 session fork',
  1004→            '`!start <prompt>` — 在当前 cwd 启动新的 SDK session',
  1005→            '`!abort` — 中止正在运行的 SDK turn',
  1006→            '`!done` / `!close` — 结束并归档当前 thread',
  1007→            '',
  1008→            '文本命令支持 `!` / `/` / 全角 `！` / `／` 前缀。',
  1009→          ].join('\n'));
  1010→        }
  1011→        break;
  1012→      }
  1013→      case '!distill': {
  1014→        if (session.threadId) {
  1015→          await this.discord.sendToThread(session.threadId, await this.buildDistillMessage(session));
  1016→        }
  1017→        break;
  1018→      }
  1019→      case '!filter': {
  1020→        const level = parts[1] as FilterLevel;
  1021→        if (!['full', 'summary', 'compact', 'silent'].includes(level)) {
  1022→          if (session.threadId) {
  1023→            await this.discord.sendToThread(session.threadId, '用法: `!filter full|summary|compact|silent`');
  1024→          }
  1025→          return;
  1026→        }
  1027→        this.registry.setFilterLevel(session.sessionId, level);
  1028→        if (session.threadId) {
  1029→          await this.discord.sendToThread(session.threadId, `过滤级别已切换为 **${level}**`);
  1030→        }
  1031→        break;
  1032→      }
  1033→      case '!info': {
  1034→        if (session.threadId) {
  1035→          await this.discord.sendToThread(session.threadId, [
  1036→            `**Session:** \`${session.sessionId.slice(0, 8)}\``,
  1037→            `**Project:** ${session.project}`,
  1038→            `**Branch:** ${session.branch}`,
  1039→            `**Directory:** \`${collapseHome(session.cwd)}\``,
  1040→            `**Filter:** ${session.filterLevel}`,
  1041→            `**Status:** ${session.status}`,
  1042→            `**Source:** ${session.source}`,
  1043→            `**Mode:** ${mode.label}`,
  1044→            `**PID:** ${session.pid}`,
  1045→            `**Reply:** ${mode.hint}`,
  1046→          ].join('\n'));
  1047→        }
  1048→        break;
  1049→      }
  1050→      case '!model': {
  1051→        const newModel = parts[1];
  1052→        if (!newModel) {
  1053→          if (session.threadId) {
  1054→            await this.discord.sendToThread(session.threadId, `当前 model: **${session.model || 'default'}**\n用法: \`!model <name-or-prefix>\``);
  1055→          }
  1056→          return;
  1057→        }
  1058→        // Warn if switching model on a hook session — will break resume
  1059→        if (session.source === 'hook') {
  1060→          if (session.threadId) {
  1061→            await this.discord.sendToThread(session.threadId, `⚠️ 切换 model 会导致无法 resume CC session（API key 不同）。仅对 \`!new\` / \`!start\` 创建的 SDK session 生效。`);
  1062→          }
  1063→          return;
  1064→        }
  1065→        const resolved = this.mmsEnv?.resolveModel(newModel);
  1066→        if (!resolved && this.mmsEnv) {
  1067→          if (session.threadId) {
  1068→            await this.discord.sendToThread(session.threadId, `未找到 model **${newModel}**。用 \`!models\` 查看可选项。`);
  1069→          }
  1070→          return;
  1071→        }
  1072→        const actualModel = resolved?.resolvedId || newModel;
  1073→        session.model = actualModel;
  1074→        if (resolved) session.provider = resolved.providerId;
  1075→        this.store.setSession(session);
  1076→        if (session.threadId) {
  1077→          const fuzzyNote = actualModel !== newModel ? `（由 "${newModel}" 模糊匹配）` : '';
  1078→          const providerInfo = resolved ? ` [${resolved.providerId}]` : '';
  1079→          await this.discord.sendToThread(session.threadId, `Model → **${actualModel}**${providerInfo}${fuzzyNote}`);
  1080→        }
  1081→        break;
  1082→      }
  1083→
  1084→      case '!models': {
  1085→        if (!this.mmsEnv) {
  1086→          if (session.threadId) await this.discord.sendToThread(session.threadId, '⚠️ 当前未配置 MMS。');
  1087→          return;
  1088→        }
  1089→        const groups = this.mmsEnv.getModelGroups();
  1090→        if (groups.length === 0) {
  1091→          if (session.threadId) await this.discord.sendToThread(session.threadId, '当前没有可用 model。');
  1092→          return;
  1093→        }
  1094→        const lines: string[] = [];
  1095→        lines.push(`来源: \`${this.mmsEnv.getRoutesPath()}\``);
  1096→        for (const group of groups) {
  1097→          lines.push(`**${group.providerId}** · \`${group.baseUrl}\``);
  1098→          lines.push(group.models.join(', '));
  1099→        }
  1100→        if (session.threadId) {
  1101→          await this.discord.sendToThread(session.threadId, lines.join('\n'));
  1102→        }
  1103→        break;
  1104→      }
  1105→
  1106→      case '!provider': {
  1107→        const newProvider = parts[1];
  1108→        if (!newProvider) {
  1109→          if (session.threadId) {
  1110→            await this.discord.sendToThread(session.threadId, `当前 provider: **${session.provider || 'default'}**\n用法: \`!provider <provider-id>\``);
  1111→          }
  1112→          return;
  1113→        }
  1114→        session.provider = newProvider;
  1115→        this.store.setSession(session);
  1116→        if (session.threadId) {
  1117→          await this.discord.sendToThread(session.threadId, `Provider → **${newProvider}**`);
  1118→        }
  1119→        break;
  1120→      }
  1121→
  1122→      case '!cd': {
  1123→        const target = parts.slice(1).join(' ');
  1124→        if (!target) {
  1125→          if (session.threadId) {
  1126→            await this.discord.sendToThread(session.threadId, `当前目录: \`${collapseHome(session.cwd)}\`\n用法: \`!cd <path-or-name>\``);
  1127→          }
  1128→          return;
  1129→        }
  1130→
  1131→        // Resolve: absolute path, ~ expansion, or fuzzy (zoxide + sessions)
  1132→        let resolved: string | null = null;
  1133→        if (target.startsWith('/')) {
  1134→          resolved = target;
  1135→        } else if (target.startsWith('~')) {
  1136→          resolved = expandHome(target);
  1137→        } else {
  1138→          resolved = this.resolveCwdShortcut(target);
