  1140→
  1141→        if (!resolved) {
  1142→          if (session.threadId) {
  1143→            await this.discord.sendToThread(session.threadId, `未找到目录: **${target}**`);
  1144→          }
  1145→          return;
  1146→        }
  1147→
  1148→        const oldCwd = session.cwd;
  1149→        session.cwd = resolved;
  1150→        session.project = resolved.split('/').pop() || session.project;
  1151→        this.store.setSession(session);
  1152→
  1153→        // Refresh hub card
  1154→        if (session.hubMessageId) {
  1155→          this.discord.sendToThread(session.threadId!, {
  1156→            embed: {
