  1158→              description: `\`${collapseHome(resolved)}\``,
  1159→              color: 0x5865F2,
  1160→            },
  1161→          }).catch(() => {});
  1162→        }
  1163→        this.registry.emit('session:active', session);
  1164→
  1165→        if (session.threadId) {
  1166→          await this.discord.sendToThread(session.threadId, `cwd → \`${collapseHome(resolved)}\``);
  1167→        }
  1168→        break;
  1169→      }
  1170→
  1171→      case '!fork': {
  1172→        if (!this.sdkManager) {
  1173→          if (session.threadId) await this.discord.sendToThread(session.threadId, '⚠️ 当前未配置 SDK。');
  1174→          return;
  1175→        }
  1176→        const forkPrompt = parts.slice(1).join(' ') || 'Continue from the forked point.';
  1177→        try {
  1178→          if (session.threadId) {
  1179→            await this.discord.sendToThread(session.threadId, '🔀 正在 fork 当前 session...');
  1180→          }
  1181→          await this.sdkManager.startSession(forkPrompt, {
  1182→            resume: session.sessionId,
  1183→            fork: true,
  1184→            cwd: session.cwd,
  1185→            model: session.model,
  1186→            provider: session.provider,
