  1188→        } catch (err) {
  1189→          if (session.threadId) {
  1190→            await this.discord.sendToThread(session.threadId, `❌ Fork 失败: ${err instanceof Error ? err.message : String(err)}`);
  1191→          }
  1192→        }
  1193→        break;
  1194→      }
  1195→
  1196→      case '!abort': {
  1197→        if (!this.sdkManager) {
  1198→          if (session.threadId) await this.discord.sendToThread(session.threadId, '⚠️ 当前未配置 SDK。');
  1199→          return;
  1200→        }
  1201→        const aborted = this.sdkManager.abort(session.sessionId);
  1202→        if (session.threadId) {
  1203→          await this.discord.sendToThread(session.threadId, aborted ? '🛑 已中止当前 SDK turn。' : '当前没有正在运行的 SDK turn。');
