  1543→  /** Update SDK session title from prompt or response text */
  1544→  private async updateSdkTitle(sessionId: string, responseText: string): Promise<void> {
  1545→    const session = this.registry.getSession(sessionId);
  1546→    if (!session?.threadId) return;
  1547→
  1548→    // Use prompt as title (user's intent), fallback to response first line
  1549→    const prompt = this.sdkLastPrompt.get(sessionId) || '';
  1550→    let summary = prompt.split('\n')[0].trim();
  1551→    summary = summary.replace(/^(please|help me|can you|I want to|I need to|请|帮我|帮忙)\s*/i, '');
  1552→
  1553→    if (!summary) {
  1554→      const lines = responseText.split('\n').map(l => l.trim()).filter(Boolean);
  1555→      for (const line of lines) {
  1556→        const cleaned = line.replace(/^#{1,4}\s*/, '').replace(/\*{1,2}/g, '').trim();
  1557→        if (cleaned.length >= 3) { summary = cleaned; break; }
  1558→      }
  1559→    }
  1560→
  1561→    if (!summary) return;
  1562→    summary = summary.length > 50 ? summary.slice(0, 47) + '...' : summary;
  1563→
  1564→    const shortId = session.sessionId.slice(0, 6);
  1565→    const title = `${session.project} / ${session.branch} — ${summary} [${shortId}]`;
  1566→    const truncated = title.length > 100 ? title.slice(0, 97) + '...' : title;
  1567→
  1568→    const updated = await this.discord.updateThreadTitle(session.threadId, truncated);
  1569→    if (!updated) return;
  1570→
  1571→    session.title = summary;
  1572→    this.store.setSession(session);
  1573→    this.registry.emit('session:active', session);
  1574→  }
  1575→
  1576→  private generateTitle(session: CLISession): string {
  1577→    const sctx = this.sessionContext.get(session.sessionId);
  1578→    const shortId = session.sessionId.slice(0, 6);
  1579→
  1580→    // Folder indicator — detect cross-folder work
  1581→    let folderPart = session.project;
  1582→    if (sctx && sctx.recentPaths.length >= 3) {
  1583→      const effective = this.detectEffectiveProject(session.cwd, sctx.recentPaths);
  1584→      if (effective && effective !== session.project) {
  1585→        folderPart = `${session.project} \u2194 ${effective}`;
  1586→        sctx.crossFolderProject = effective;
  1587→      }
  1588→    }
  1589→
  1590→    // Base: "project ↔ target / branch"
  1591→    let title = `${folderPart} / ${session.branch}`;
  1592→
  1593→    // Context from latest prompt
  1594→    if (sctx?.latestPrompt) {
  1595→      let prompt = sctx.latestPrompt.split('\n')[0].trim();
  1596→      // Trim common prefixes
  1597→      prompt = prompt.replace(/^(please|help me|can you|I want to|I need to|请|帮我|帮忙)\s*/i, '');
  1598→      const maxLen = 100 - title.length - shortId.length - 7; // 7 = " — " + " [" + "]"
  1599→      if (prompt && maxLen > 10) {
  1600→        const truncated = prompt.length > maxLen ? prompt.slice(0, maxLen - 1) + '\u2026' : prompt;
  1601→        title += ` \u2014 ${truncated}`;
  1602→      }
  1603→    }
  1604→
  1605→    title += ` [${shortId}]`;
  1606→    return title.length > 100 ? title.slice(0, 97) + '...' : title;
  1607→  }
  1608→
  1609→  /** Detect if tool activity targets a different project than session cwd */
  1610→  private detectEffectiveProject(sessionCwd: string, paths: string[]): string | null {
  1611→    if (paths.length < 3) return null;
  1612→    const cwdNorm = sessionCwd.endsWith('/') ? sessionCwd : sessionCwd + '/';
  1613→
  1614→    // Find paths outside session cwd
  1615→    const outsidePaths = paths.filter(p => p.startsWith('/') && !p.startsWith(cwdNorm));
  1616→    if (outsidePaths.length < 3 || outsidePaths.length / paths.length < 0.3) return null;
  1617→
  1618→    // Extract project name at the path divergence point
  1619→    const cwdParts = sessionCwd.split('/');
  1620→    const projects = new Map<string, number>();
  1621→
  1622→    for (const p of outsidePaths) {
  1623→      const parts = p.split('/');
  1624→      let divergeAt = 0;
  1625→      for (let i = 0; i < Math.min(parts.length, cwdParts.length); i++) {
  1626→        if (parts[i] !== cwdParts[i]) { divergeAt = i; break; }
  1627→        divergeAt = i + 1;
  1628→      }
  1629→      const name = parts[divergeAt];
  1630→      if (name) projects.set(name, (projects.get(name) || 0) + 1);
  1631→    }
  1632→
  1633→    let dominant: string | null = null;
  1634→    let maxCount = 0;
  1635→    for (const [name, count] of projects) {
  1636→      if (count > maxCount) { maxCount = count; dominant = name; }
  1637→    }
  1638→    return dominant;
  1639→  }
