  1714→  private renderEvent(eventType: string, data: unknown, agent?: string): RenderedMessage {
  1715→    const brand = getAgentBrand(agent || 'unknown');
  1716→    const author = { name: brand.label, ...(brand.iconUrl ? { icon_url: brand.iconUrl } : {}) };
  1717→    switch (eventType) {
  1718→      case 'text':
  1719→        return { text: String(data) };
  1720→
  1721→      case 'user_prompt': {
  1722→        const d = data as { prompt?: string };
  1723→        const prompt = d.prompt || String(data);
  1724→        const truncated = prompt.length > 500 ? prompt.slice(0, 500) + '...' : prompt;
  1725→        return { text: `**User:** ${truncated}` };
  1726→      }
  1727→
  1728→      case 'tool_use': {
  1729→        const d = data as { name?: string; input?: unknown };
  1730→        const inp = this.parseInput(d.input);
  1731→        let summary = '';
  1732→        if (inp.command) summary = `\`${String(inp.command).slice(0, 100)}\``;
  1733→        else if (inp.file_path) summary = `\`${String(inp.file_path)}\``;
  1734→        else if (inp.pattern) summary = `\`${String(inp.pattern)}\``;
  1735→        return { text: `**${d.name || 'unknown'}** ${summary}`.trim() };
  1736→      }
  1737→
  1738→      case 'tool_result': {
  1739→        const d = data as { tool?: string; input?: unknown; output?: unknown; content?: string; is_error?: boolean };
  1740→        const tool = d.tool || 'unknown';
  1741→        const isError = d.is_error === true;
  1742→
  1743→        // Parse input (may be JSON string from hook's jq -c)
  1744→        const inp = this.parseInput(d.input);
  1745→        let inputSummary = '';
  1746→        if (inp.command) inputSummary = String(inp.command).slice(0, 100);
  1747→        else if (inp.file_path) inputSummary = String(inp.file_path);
  1748→        else if (inp.pattern) inputSummary = String(inp.pattern);
  1749→        else if (inp.query) inputSummary = String(inp.query).slice(0, 100);
  1750→
  1751→        // Extract readable text from output (handles string, content-block arrays, and wrapped objects)
  1752→        let output = this.extractOutputText(d.output);
  1753→        if (!output && d.content) output = d.content;
  1754→
  1755→        // Build embed with description (renders with visible colored side bar)
  1756→        const titleLine = `${isError ? '\u274c' : '\ud83d\udd27'} ${tool}${inputSummary ? ` \u2014 ${inputSummary}` : ''}`;
  1757→        let description: string | undefined;
  1758→        if (output) {
  1759→          const truncated = output.length > 800
  1760→            ? output.slice(0, 800) + `\n[truncated, ${output.length} chars total]`
  1761→            : output;
  1762→          description = `\`\`\`\n${truncated}\n\`\`\``;
  1763→        }
  1764→
  1765→        return {
  1766→          embed: {
  1767→            author,
  1768→            title: titleLine.length > 256 ? titleLine.slice(0, 253) + '...' : titleLine,
  1769→            description,
  1770→            color: isError ? 0xED4245 : 0x57F287,
  1771→            timestamp: new Date().toISOString(),
  1772→          },
  1773→        };
  1774→      }
  1775→
  1776→      case 'error':
  1777→        return {
  1778→          embed: {
  1779→            author,
  1780→            title: '\ud83d\udea8 Error',
  1781→            description: String(data),
  1782→            color: 0xED4245,
  1783→          },
  1784→        };
  1785→
  1786→      case 'result': {
  1787→        const d = data as { usage?: { cost_usd?: number; input_tokens?: number; output_tokens?: number } };
  1788→        const usage = d.usage;
  1789→        return {
  1790→          embed: {
  1791→            author,
  1792→            title: '\u2705 Done',
  1793→            color: 0x57F287,
  1794→            ...(usage ? {
  1795→              footer: {
  1796→                text: `Cost: $${(usage.cost_usd || 0).toFixed(4)} | In: ${usage.input_tokens} | Out: ${usage.output_tokens}`,
  1797→              },
  1798→            } : {}),
  1799→          },
  1800→        };
  1801→      }
  1802→
  1803→      case 'notification': {
  1804→        if (typeof data === 'string') return { text: data };
  1805→        const nd = data as Record<string, unknown>;
  1806→        const raw = nd.message ?? nd.title ?? nd.summary;
  1807→        // Ensure we always produce a string — nd.message may be an object in some Claude Code versions
  1808→        const summary = typeof raw === 'string'
  1809→          ? raw
  1810→          : (raw != null ? JSON.stringify(raw, null, 2) : JSON.stringify(data, null, 2));
  1811→        if (!summary) return { text: '' };
  1812→        const truncated = summary.length > 500 ? summary.slice(0, 500) + '...' : summary;
  1813→        return { text: truncated };
  1814→      }
  1815→
  1816→      default:
  1817→        return { text: `[${eventType}] ${typeof data === 'string' ? data : JSON.stringify(data, null, 2)}` };
  1818→    }
  1819→  }
  1820→}
